/**
 * Bank B Fix — adds 27 diagnostic questions to the 6 new KAP Sci/SS courses,
 * 1 missing question to G7TECH, and 27 questions to APHG.
 */
import { createConnection } from 'mysql2/promise';

const db = await createConnection(process.env.DATABASE_URL);

// ─── helpers ────────────────────────────────────────────────────────────────
const mc = (text, choices, correct, explanation, unit, difficulty = 'medium') => ({
  questionText: text,
  questionType: 'multiple_choice',
  choices: JSON.stringify(choices),
  correctAnswer: correct,
  mapsToUnit: String(unit),
  mapsToSkills: JSON.stringify([]),
  difficulty,
  explanation,
  sortOrder: 0,
});

async function getCourseId(code) {
  const [rows] = await db.execute('SELECT id FROM courses WHERE courseCode = ?', [code]);
  if (!rows.length) throw new Error(`Course not found: ${code}`);
  return rows[0].id;
}

async function getExistingCount(courseId) {
  const [rows] = await db.execute('SELECT COUNT(*) AS cnt FROM diagnosticQuestions WHERE courseId = ?', [courseId]);
  return Number(rows[0].cnt);
}

async function insertQuestions(courseId, questions) {
  for (let i = 0; i < questions.length; i++) {
    const q = questions[i];
    const qId = `DIAG-${courseId}-B-${String(i + 1).padStart(3, '0')}`;
    await db.execute(
      `INSERT INTO diagnosticQuestions
       (questionId, questionText, questionType, choices, correctAnswer, mapsToUnit, mapsToSkills, difficulty, explanation, sortOrder, courseId)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
      [qId, q.questionText, q.questionType, q.choices, q.correctAnswer, q.mapsToUnit, q.mapsToSkills, q.difficulty, q.explanation, q.sortOrder, courseId]
    );
  }
}

// ─── G6KAPSCI Bank B (27 questions) ─────────────────────────────────────────
function getG6KAPSciB() {
  return [
    // Unit 1 — Matter & Energy (2 more)
    mc('Which property best describes a substance that cannot be broken down into simpler substances by chemical means?', ['A. Mixture', 'B. Compound', 'C. Element', 'D. Solution'], 'C', 'An element is a pure substance that cannot be broken down by chemical means.', '1', 'easy'),
    mc('When iron rusts, what type of change occurs?', ['A. Physical change', 'B. Chemical change', 'C. Nuclear change', 'D. No change'], 'B', 'Rusting is a chemical change because a new substance (iron oxide) is formed.', '1', 'medium'),
    // Unit 2 — Forces & Motion (2 more)
    mc('A car accelerates from 0 to 60 mph in 10 seconds. What is its average acceleration?', ['A. 6 mph/s', 'B. 60 mph/s', 'C. 600 mph/s', 'D. 0.6 mph/s'], 'A', 'Acceleration = change in velocity / time = 60/10 = 6 mph/s.', '2', 'medium'),
    mc('Which of Newton\'s laws states that an object in motion stays in motion unless acted upon by an external force?', ['A. First Law', 'B. Second Law', 'C. Third Law', 'D. Law of Gravitation'], 'A', 'Newton\'s First Law (Law of Inertia) describes objects maintaining their state of motion.', '2', 'easy'),
    // Unit 3 — Earth Systems (2 more)
    mc('Which layer of Earth is responsible for generating Earth\'s magnetic field?', ['A. Crust', 'B. Mantle', 'C. Outer core', 'D. Inner core'], 'C', 'The liquid outer core generates Earth\'s magnetic field through convection of molten iron.', '3', 'medium'),
    mc('What drives the movement of tectonic plates?', ['A. Solar radiation', 'B. Convection currents in the mantle', 'C. Ocean tides', 'D. Earth\'s rotation'], 'B', 'Convection currents in the mantle transfer heat and drive plate movement.', '3', 'medium'),
    // Unit 4 — Ecosystems (2 more)
    mc('Which term describes all the living and non-living components of an environment?', ['A. Community', 'B. Population', 'C. Ecosystem', 'D. Biome'], 'C', 'An ecosystem includes both biotic (living) and abiotic (non-living) components.', '4', 'easy'),
    mc('In a food web, which organism is always a producer?', ['A. Hawk', 'B. Rabbit', 'C. Grass', 'D. Fox'], 'C', 'Producers (plants) make their own food through photosynthesis.', '4', 'easy'),
    // Unit 5 — Cells & Life Processes (2 more)
    mc('What is the function of the cell membrane?', ['A. Produces energy', 'B. Controls what enters and exits the cell', 'C. Stores genetic information', 'D. Makes proteins'], 'B', 'The cell membrane is selectively permeable, controlling the movement of substances.', '5', 'easy'),
    mc('Which process converts glucose into usable energy in cells?', ['A. Photosynthesis', 'B. Cellular respiration', 'C. Fermentation', 'D. Osmosis'], 'B', 'Cellular respiration breaks down glucose to produce ATP energy.', '5', 'medium'),
    // Unit 6 — Genetics & Heredity (2 more)
    mc('What is a gene?', ['A. A type of protein', 'B. A segment of DNA that codes for a trait', 'C. A chromosome', 'D. A cell organelle'], 'B', 'A gene is a specific sequence of DNA that codes for a particular trait or protein.', '6', 'easy'),
    mc('If both parents carry one recessive allele for a trait, what is the probability their child will show the recessive trait?', ['A. 0%', 'B. 25%', 'C. 50%', 'D. 100%'], 'B', 'With two Aa parents, the Punnett square gives 25% aa (recessive phenotype).', '6', 'hard'),
    // Unit 7 — Space Science (2 more)
    mc('What causes the phases of the Moon?', ['A. Earth\'s shadow on the Moon', 'B. The Moon\'s rotation', 'C. The changing angle of sunlight on the Moon as seen from Earth', 'D. Clouds blocking the Moon'], 'C', 'Moon phases result from our changing view of the sunlit portion of the Moon as it orbits Earth.', '7', 'medium'),
    mc('Which planet has the most moons in our solar system?', ['A. Jupiter', 'B. Saturn', 'C. Uranus', 'D. Neptune'], 'B', 'Saturn has the most confirmed moons (over 140 as of recent discoveries).', '7', 'medium'),
    // Unit 8 — Scientific Investigation (2 more)
    mc('What is the purpose of a control group in an experiment?', ['A. To test the hypothesis', 'B. To provide a baseline for comparison', 'C. To increase sample size', 'D. To eliminate all variables'], 'B', 'A control group provides a standard baseline against which experimental results are compared.', '8', 'easy'),
    mc('Which type of graph is best for showing change over time?', ['A. Bar graph', 'B. Pie chart', 'C. Line graph', 'D. Scatter plot'], 'C', 'Line graphs are ideal for displaying trends and changes over time.', '8', 'easy'),
    // Prerequisite (3 more)
    mc('What is the difference between a hypothesis and a theory?', ['A. They are the same thing', 'B. A hypothesis is tested; a theory is well-supported by evidence', 'C. A theory is untested; a hypothesis is proven', 'D. Neither can be tested'], 'B', 'A hypothesis is a testable prediction; a scientific theory is a well-substantiated explanation supported by extensive evidence.', 'prereq', 'medium'),
    mc('Which of the following is an example of potential energy?', ['A. A moving car', 'B. A stretched rubber band', 'C. A spinning top', 'D. Sound waves'], 'B', 'A stretched rubber band stores elastic potential energy.', 'prereq', 'easy'),
    mc('What does the law of conservation of energy state?', ['A. Energy can be created from nothing', 'B. Energy can be destroyed in chemical reactions', 'C. Energy cannot be created or destroyed, only transformed', 'D. Energy always decreases over time'], 'C', 'The law of conservation of energy states that total energy in a closed system remains constant.', 'prereq', 'medium'),
    // Additional harder questions
    mc('A scientist observes that plants grow taller when given more light. This is an example of a(n):', ['A. Theory', 'B. Law', 'C. Hypothesis', 'D. Observation'], 'D', 'This is a direct observation. A hypothesis would be a proposed explanation for why this occurs.', '8', 'medium'),
    mc('Which type of rock forms from cooling magma?', ['A. Sedimentary', 'B. Metamorphic', 'C. Igneous', 'D. Composite'], 'C', 'Igneous rocks form when magma or lava cools and solidifies.', '3', 'easy'),
    mc('What is the role of decomposers in an ecosystem?', ['A. Produce food through photosynthesis', 'B. Break down dead organisms and recycle nutrients', 'C. Consume primary producers', 'D. Regulate population sizes'], 'B', 'Decomposers break down dead organic matter, returning nutrients to the soil.', '4', 'easy'),
    mc('Which organelle is known as the "powerhouse of the cell"?', ['A. Nucleus', 'B. Ribosome', 'C. Mitochondria', 'D. Vacuole'], 'C', 'Mitochondria produce ATP through cellular respiration, earning the "powerhouse" nickname.', '5', 'easy'),
    mc('What is the atomic number of an element?', ['A. The number of neutrons', 'B. The number of protons', 'C. The total mass of the atom', 'D. The number of electrons in the outer shell'], 'B', 'The atomic number equals the number of protons in the nucleus, which defines the element.', '1', 'easy'),
    mc('Which force keeps planets in orbit around the Sun?', ['A. Magnetic force', 'B. Nuclear force', 'C. Gravitational force', 'D. Electromagnetic force'], 'C', 'Gravity is the attractive force between masses that keeps planets in their orbital paths.', '7', 'easy'),
    mc('What is the difference between speed and velocity?', ['A. They are identical', 'B. Velocity includes direction; speed does not', 'C. Speed includes direction; velocity does not', 'D. Velocity is always greater than speed'], 'B', 'Velocity is a vector quantity that includes both magnitude (speed) and direction.', '2', 'medium'),
    mc('Which process in plants converts carbon dioxide and water into glucose using sunlight?', ['A. Cellular respiration', 'B. Fermentation', 'C. Photosynthesis', 'D. Transpiration'], 'C', 'Photosynthesis uses light energy to convert CO₂ and H₂O into glucose and oxygen.', '5', 'easy'),
  ];
}

// ─── G6KAPSS Bank B (27 questions) ──────────────────────────────────────────
function getG6KAPSSb() {
  return [
    mc('Which ancient civilization developed the first writing system?', ['A. Egypt', 'B. Mesopotamia (Sumerians)', 'C. Indus Valley', 'D. China'], 'B', 'The Sumerians of Mesopotamia developed cuneiform, one of the earliest writing systems, around 3200 BCE.', '1', 'medium'),
    mc('What is the primary purpose of a constitution in a government?', ['A. To collect taxes', 'B. To establish and limit government powers', 'C. To declare war', 'D. To manage the economy'], 'B', 'A constitution establishes the framework of government and limits its powers to protect citizens\' rights.', '2', 'medium'),
    mc('Which geographic feature most influenced the development of early civilizations?', ['A. Mountains', 'B. Deserts', 'C. River valleys', 'D. Forests'], 'C', 'River valleys provided fertile soil, water, and transportation routes essential for early civilizations.', '1', 'easy'),
    mc('What economic system is based on supply and demand with private ownership?', ['A. Communism', 'B. Socialism', 'C. Market economy', 'D. Command economy'], 'C', 'A market economy (capitalism) is based on private ownership and the forces of supply and demand.', '3', 'medium'),
    mc('Which of the following best describes a primary source?', ['A. A textbook about World War II', 'B. A documentary film', 'C. A diary written by a soldier during World War II', 'D. An encyclopedia article'], 'C', 'A primary source is an original document or artifact created at the time of the event being studied.', '8', 'easy'),
    mc('What is the significance of the Magna Carta (1215)?', ['A. It established democracy in England', 'B. It limited the power of the king and protected certain rights', 'C. It ended the Crusades', 'D. It created the British Parliament'], 'B', 'The Magna Carta was a landmark document that limited royal power and established that the king was subject to the law.', '2', 'medium'),
    mc('Which factor most contributed to the spread of the Black Death in medieval Europe?', ['A. Lack of hospitals', 'B. Trade routes connecting Asia and Europe', 'C. Religious conflicts', 'D. Poor farming techniques'], 'B', 'Trade routes facilitated the rapid spread of the plague from Asia to Europe in the 14th century.', '4', 'medium'),
    mc('What is the difference between a renewable and non-renewable resource?', ['A. Renewable resources are more expensive', 'B. Renewable resources can be replenished naturally; non-renewable cannot', 'C. Non-renewable resources are better for the environment', 'D. There is no difference'], 'B', 'Renewable resources (like solar, wind) replenish naturally; non-renewable resources (like oil, coal) take millions of years to form.', '5', 'easy'),
    mc('Which civilization built the Great Wall of China?', ['A. The Han Dynasty', 'B. Multiple Chinese dynasties over centuries', 'C. The Mongols', 'D. The Tang Dynasty'], 'B', 'The Great Wall was built and extended by multiple Chinese dynasties, beginning as early as the 7th century BCE.', '1', 'medium'),
    mc('What is the purpose of the United Nations?', ['A. To govern all countries', 'B. To promote international peace, security, and cooperation', 'C. To control world trade', 'D. To enforce human rights laws'], 'B', 'The UN was founded in 1945 to promote international peace, security, and cooperation among nations.', '6', 'easy'),
    mc('How does geography influence cultural development?', ['A. It has no influence', 'B. Physical features shape trade, food, shelter, and social organization', 'C. Only climate matters', 'D. Culture develops independently of geography'], 'B', 'Geography shapes how people live, what they eat, how they trade, and how their societies are organized.', '7', 'medium'),
    mc('What was the Silk Road?', ['A. A road made of silk in China', 'B. An ancient network of trade routes connecting Asia, Africa, and Europe', 'C. A sea route to India', 'D. A Roman road system'], 'B', 'The Silk Road was an ancient network of trade routes that connected China with Central Asia, the Middle East, and Europe.', '4', 'medium'),
    mc('Which type of government is led by a single ruler with absolute power?', ['A. Democracy', 'B. Republic', 'C. Autocracy/Dictatorship', 'D. Oligarchy'], 'C', 'An autocracy or dictatorship is a form of government where one person holds absolute power.', '2', 'easy'),
    mc('What is the concept of "checks and balances" in government?', ['A. Balancing the national budget', 'B. A system where each branch of government limits the power of the others', 'C. Counting votes in elections', 'D. Managing government spending'], 'B', 'Checks and balances ensure no single branch of government becomes too powerful by giving each branch ways to limit the others.', '2', 'medium'),
    mc('Which ancient wonder was located in Egypt?', ['A. The Colosseum', 'B. The Parthenon', 'C. The Great Pyramid of Giza', 'D. The Hanging Gardens of Babylon'], 'C', 'The Great Pyramid of Giza is the only ancient wonder still largely intact and is located in Egypt.', '1', 'easy'),
    mc('What is the main difference between immigration and emigration?', ['A. They are the same thing', 'B. Immigration is moving into a country; emigration is leaving a country', 'C. Emigration is moving into a country; immigration is leaving', 'D. Only immigration is voluntary'], 'B', 'Immigration refers to entering a new country to live; emigration refers to leaving one\'s home country.', '7', 'easy'),
    mc('Which economic concept describes the cost of the next best alternative given up when making a choice?', ['A. Supply', 'B. Demand', 'C. Opportunity cost', 'D. Inflation'], 'C', 'Opportunity cost is the value of the next best alternative foregone when a decision is made.', '3', 'medium'),
    mc('What was the Renaissance?', ['A. A period of religious wars in Europe', 'B. A cultural and intellectual movement in Europe featuring renewed interest in classical learning', 'C. The fall of the Roman Empire', 'D. The beginning of the Industrial Revolution'], 'B', 'The Renaissance (14th–17th centuries) was a cultural movement that revived interest in classical Greek and Roman learning and produced great art, literature, and science.', '4', 'medium'),
    mc('How did the invention of the printing press change society?', ['A. It made books more expensive', 'B. It spread ideas more rapidly and increased literacy', 'C. It replaced handwriting permanently', 'D. It had little impact on society'], 'B', 'Gutenberg\'s printing press (c. 1440) enabled mass production of books, spreading ideas rapidly and contributing to the Reformation and Scientific Revolution.', '4', 'hard'),
    mc('What is the purpose of a map\'s legend (key)?', ['A. To show the map\'s scale', 'B. To explain the symbols and colors used on the map', 'C. To indicate the map\'s orientation', 'D. To list the map\'s sources'], 'B', 'A map legend explains what the symbols, colors, and patterns on the map represent.', '7', 'easy'),
    mc('Which factor most contributed to the fall of the Roman Empire?', ['A. A single cause', 'B. Multiple factors including military pressure, economic problems, and political instability', 'C. Only barbarian invasions', 'D. Only economic collapse'], 'B', 'The fall of Rome resulted from a combination of factors including military overextension, economic troubles, political corruption, and external invasions.', '4', 'hard'),
    mc('What is the difference between a democracy and a republic?', ['A. They are identical', 'B. In a democracy citizens vote directly; in a republic they elect representatives', 'C. A republic has a president; a democracy has a prime minister', 'D. Only republics have constitutions'], 'B', 'Direct democracy involves citizens voting on laws directly; a republic uses elected representatives to make decisions.', '2', 'medium'),
    mc('Which of the following best describes the concept of cultural diffusion?', ['A. The disappearance of a culture', 'B. The spread of cultural elements from one society to another', 'C. The isolation of a culture', 'D. The creation of a new culture'], 'B', 'Cultural diffusion is the process by which cultural elements (ideas, customs, technologies) spread from one society to another.', '7', 'medium'),
    mc('What was the significance of the Columbian Exchange?', ['A. It established trade between North and South America only', 'B. It transferred plants, animals, diseases, and ideas between the Americas and the Old World', 'C. It was a peace treaty between Spain and Portugal', 'D. It established the first global currency'], 'B', 'The Columbian Exchange (after 1492) involved the widespread transfer of plants, animals, diseases, and ideas between the Americas and Europe, Africa, and Asia.', '4', 'hard'),
    mc('What is the role of citizens in a democratic government?', ['A. To obey laws only', 'B. To vote, pay taxes, and participate in civic life', 'C. To serve in the military', 'D. To have no role'], 'B', 'In a democracy, citizens have responsibilities including voting, jury duty, paying taxes, and civic participation.', '2', 'easy'),
    mc('Which geographic concept describes the relationship between people and their environment?', ['A. Absolute location', 'B. Human-environment interaction', 'C. Region', 'D. Movement'], 'B', 'Human-environment interaction is one of the five themes of geography, describing how people affect and are affected by their environment.', '7', 'medium'),
    mc('What is the difference between a city-state and an empire?', ['A. They are the same', 'B. A city-state is a self-governing city; an empire controls many territories', 'C. An empire is smaller than a city-state', 'D. Only empires have governments'], 'B', 'A city-state (like ancient Athens) is an independent city with its own government; an empire (like Rome) controls many territories and peoples.', '1', 'medium'),
  ];
}

// ─── G7KAPSCI Bank B (27 questions) ─────────────────────────────────────────
function getG7KAPSciB() {
  return [
    mc('What is the difference between a physical and chemical change?', ['A. Physical changes are permanent; chemical are not', 'B. Physical changes alter form but not composition; chemical changes create new substances', 'C. Chemical changes are reversible; physical are not', 'D. They are the same'], 'B', 'Physical changes alter the form or appearance of matter; chemical changes produce new substances with different properties.', '1', 'easy'),
    mc('Which type of wave requires a medium to travel?', ['A. Light waves', 'B. Radio waves', 'C. Sound waves', 'D. X-rays'], 'C', 'Sound waves are mechanical waves that require a medium (solid, liquid, or gas) to propagate.', '2', 'easy'),
    mc('What is the difference between mitosis and meiosis?', ['A. They are identical processes', 'B. Mitosis produces 2 identical cells; meiosis produces 4 genetically unique cells', 'C. Meiosis produces 2 cells; mitosis produces 4', 'D. Only meiosis occurs in humans'], 'B', 'Mitosis produces 2 genetically identical diploid cells for growth/repair; meiosis produces 4 haploid cells for reproduction.', '3', 'hard'),
    mc('What is the role of DNA in living organisms?', ['A. Provides energy', 'B. Carries genetic information and instructions for building proteins', 'C. Transports oxygen', 'D. Digests food'], 'B', 'DNA contains the genetic instructions used in the development, functioning, growth, and reproduction of all known organisms.', '4', 'easy'),
    mc('Which process describes water moving from soil into plant roots?', ['A. Transpiration', 'B. Photosynthesis', 'C. Osmosis', 'D. Diffusion'], 'C', 'Osmosis is the movement of water across a semi-permeable membrane from an area of high water concentration to low.', '5', 'medium'),
    mc('What causes seasons on Earth?', ['A. Earth\'s distance from the Sun', 'B. Earth\'s axial tilt as it orbits the Sun', 'C. The Moon\'s gravitational pull', 'D. Solar flares'], 'B', 'Earth\'s 23.5° axial tilt causes different parts of Earth to receive more direct sunlight at different times of year.', '6', 'medium'),
    mc('Which type of rock forms from heat and pressure deep underground?', ['A. Igneous', 'B. Sedimentary', 'C. Metamorphic', 'D. Volcanic'], 'C', 'Metamorphic rocks form when existing rocks are transformed by heat, pressure, or chemical processes deep in Earth\'s crust.', '7', 'easy'),
    mc('What is the function of antibodies in the immune system?', ['A. Carry oxygen in blood', 'B. Recognize and neutralize pathogens', 'C. Produce red blood cells', 'D. Regulate body temperature'], 'B', 'Antibodies are proteins produced by B cells that recognize and bind to specific antigens on pathogens to neutralize them.', '8', 'medium'),
    mc('What is the law of conservation of mass?', ['A. Mass can be created in chemical reactions', 'B. Mass is destroyed in nuclear reactions', 'C. The total mass of reactants equals the total mass of products in a chemical reaction', 'D. Mass and energy are unrelated'], 'C', 'The law of conservation of mass states that matter is neither created nor destroyed in a chemical reaction.', 'prereq', 'medium'),
    mc('Which organelle contains chlorophyll and is the site of photosynthesis?', ['A. Mitochondria', 'B. Nucleus', 'C. Chloroplast', 'D. Vacuole'], 'C', 'Chloroplasts contain chlorophyll and are the sites of photosynthesis in plant cells.', '5', 'easy'),
    mc('What is the difference between a food chain and a food web?', ['A. They are identical', 'B. A food chain shows one path of energy; a food web shows multiple interconnected paths', 'C. A food web shows only producers', 'D. A food chain is more complex'], 'B', 'A food chain shows a single linear sequence of energy transfer; a food web shows the complex network of feeding relationships.', '5', 'easy'),
    mc('What is the pH scale used to measure?', ['A. Temperature', 'B. Pressure', 'C. Acidity or alkalinity of a solution', 'D. Electrical charge'], 'C', 'The pH scale (0-14) measures the concentration of hydrogen ions, indicating how acidic or basic a solution is.', '1', 'easy'),
    mc('Which type of reproduction produces offspring genetically identical to the parent?', ['A. Sexual reproduction', 'B. Asexual reproduction', 'C. Cross-pollination', 'D. Fertilization'], 'B', 'Asexual reproduction produces genetically identical offspring (clones) from a single parent without fertilization.', '4', 'easy'),
    mc('What is the difference between speed and acceleration?', ['A. They are the same', 'B. Speed is rate of motion; acceleration is rate of change of velocity', 'C. Acceleration is always greater than speed', 'D. Speed includes direction'], 'B', 'Speed measures how fast an object moves; acceleration measures how quickly velocity (speed and/or direction) changes.', '2', 'medium'),
    mc('Which process forms sedimentary rocks?', ['A. Cooling of magma', 'B. Heat and pressure', 'C. Deposition and compaction of sediments', 'D. Volcanic eruption'], 'C', 'Sedimentary rocks form when sediments (sand, silt, organic material) are deposited, compacted, and cemented over time.', '7', 'easy'),
    mc('What is natural selection?', ['A. Humans choosing which animals to breed', 'B. The process by which organisms with favorable traits survive and reproduce more successfully', 'C. Random changes in DNA', 'D. The extinction of species'], 'B', 'Natural selection is the mechanism of evolution where organisms with traits better suited to their environment survive and reproduce more.', '4', 'hard'),
    mc('Which type of energy is stored in chemical bonds?', ['A. Kinetic energy', 'B. Nuclear energy', 'C. Chemical potential energy', 'D. Thermal energy'], 'C', 'Chemical potential energy is stored in the bonds between atoms and molecules and is released during chemical reactions.', '1', 'medium'),
    mc('What is the function of the nervous system?', ['A. Transport oxygen', 'B. Digest food', 'C. Detect stimuli and coordinate body responses', 'D. Produce hormones'], 'C', 'The nervous system detects internal and external stimuli and coordinates the body\'s responses through electrical signals.', '8', 'easy'),
    mc('Which gas makes up the largest percentage of Earth\'s atmosphere?', ['A. Oxygen', 'B. Carbon dioxide', 'C. Nitrogen', 'D. Argon'], 'C', 'Nitrogen makes up about 78% of Earth\'s atmosphere, followed by oxygen at about 21%.', '6', 'easy'),
    mc('What is the difference between a renewable and non-renewable energy source?', ['A. Renewable energy is more powerful', 'B. Renewable sources replenish naturally; non-renewable sources take millions of years to form', 'C. Non-renewable sources are cleaner', 'D. There is no difference'], 'B', 'Renewable energy (solar, wind, hydro) replenishes naturally; non-renewable energy (fossil fuels) takes millions of years to form.', '7', 'easy'),
    mc('What is the role of the nucleus in a cell?', ['A. Produce energy', 'B. Control cell activities and store genetic information', 'C. Digest waste materials', 'D. Transport materials'], 'B', 'The nucleus is the control center of the cell, containing DNA and directing cell activities and reproduction.', '3', 'easy'),
    mc('Which type of wave has the highest frequency in the electromagnetic spectrum?', ['A. Radio waves', 'B. Visible light', 'C. Infrared waves', 'D. Gamma rays'], 'D', 'Gamma rays have the highest frequency (and shortest wavelength) in the electromagnetic spectrum.', '2', 'medium'),
    mc('What is the difference between a biotic and abiotic factor?', ['A. They are the same', 'B. Biotic factors are living; abiotic factors are non-living', 'C. Abiotic factors are living; biotic are non-living', 'D. Only biotic factors affect ecosystems'], 'B', 'Biotic factors are living components (plants, animals, bacteria); abiotic factors are non-living (temperature, water, sunlight).', '5', 'easy'),
    mc('What is the purpose of a scientific model?', ['A. To replace experiments', 'B. To represent and explain complex phenomena', 'C. To prove theories wrong', 'D. To collect data'], 'B', 'Scientific models represent complex systems or phenomena to help explain, predict, and understand them.', 'prereq', 'easy'),
    mc('Which process in the water cycle involves water changing from liquid to gas?', ['A. Condensation', 'B. Precipitation', 'C. Evaporation', 'D. Infiltration'], 'C', 'Evaporation is the process by which liquid water is converted to water vapor (gas) by heat energy.', '6', 'easy'),
    mc('What is the difference between a hypothesis and a prediction?', ['A. They are identical', 'B. A hypothesis is a testable explanation; a prediction is a specific expected outcome', 'C. A prediction is broader than a hypothesis', 'D. Only hypotheses can be tested'], 'B', 'A hypothesis is a proposed explanation for an observation; a prediction is a specific, testable statement about what will happen.', 'prereq', 'medium'),
    mc('Which type of mutation changes a single base pair in DNA?', ['A. Chromosomal mutation', 'B. Frameshift mutation', 'C. Point mutation', 'D. Deletion mutation'], 'C', 'A point mutation (substitution) changes a single nucleotide base pair in the DNA sequence.', '4', 'hard'),
  ];
}

// ─── G7KAPSS Bank B (27 questions) ──────────────────────────────────────────
function getG7KAPSSb() {
  return [
    mc('What is the significance of the Texas Revolution (1835-1836)?', ['A. Texas became a US state immediately', 'B. Texas gained independence from Mexico and became the Republic of Texas', 'C. Mexico gained control of Texas', 'D. Texas joined the Confederacy'], 'B', 'The Texas Revolution resulted in Texas declaring independence from Mexico in 1836, establishing the Republic of Texas.', '1', 'easy'),
    mc('What is the purpose of the Texas Constitution?', ['A. To govern the United States', 'B. To establish the framework of Texas state government and protect citizens\' rights', 'C. To declare independence from Mexico', 'D. To manage Texas\'s economy'], 'B', 'The Texas Constitution establishes the structure of state government, defines the rights of Texans, and limits government power.', '2', 'medium'),
    mc('Which geographic region of Texas is known for its flat, treeless landscape and cattle ranching?', ['A. Piney Woods', 'B. Gulf Coast', 'C. Great Plains', 'D. Hill Country'], 'C', 'The Great Plains (including the Llano Estacado) is characterized by flat terrain and has historically been important for cattle ranching.', '3', 'medium'),
    mc('What was the significance of the Battle of the Alamo (1836)?', ['A. Texas won the battle and independence', 'B. Despite defeat, it rallied Texan forces with "Remember the Alamo" as a battle cry', 'C. Mexico surrendered after the battle', 'D. The US Army helped defend the Alamo'], 'B', 'Though the defenders were defeated, the Battle of the Alamo became a symbol of Texas resistance and inspired the final victory at San Jacinto.', '1', 'medium'),
    mc('Which Native American group was the dominant force on the Southern Plains of Texas in the 1800s?', ['A. Cherokee', 'B. Apache', 'C. Comanche', 'D. Kiowa'], 'C', 'The Comanche Nation was the dominant power on the Southern Plains, known as "Comancheria," controlling much of Texas in the 19th century.', '4', 'medium'),
    mc('What is the role of the Texas Legislature?', ['A. Enforce laws', 'B. Interpret laws', 'C. Make laws for the state of Texas', 'D. Manage the military'], 'C', 'The Texas Legislature (bicameral: Senate and House of Representatives) is the lawmaking branch of Texas state government.', '2', 'easy'),
    mc('How did the discovery of oil at Spindletop (1901) affect Texas?', ['A. It had little economic impact', 'B. It transformed Texas into a major industrial and economic power', 'C. It caused environmental damage only', 'D. It led to Texas leaving the Union'], 'B', 'The Spindletop oil discovery launched the Texas oil industry, transforming the state\'s economy and making it a major industrial power.', '5', 'medium'),
    mc('What is the difference between a primary and secondary source in historical research?', ['A. They are the same', 'B. Primary sources are original documents from the time; secondary sources analyze primary sources', 'C. Secondary sources are more reliable', 'D. Primary sources are always written'], 'B', 'Primary sources (diaries, photographs, original documents) come from the time period; secondary sources (textbooks, analyses) interpret primary sources.', '6', 'easy'),
    mc('Which factor most contributed to the growth of the cattle industry in Texas after the Civil War?', ['A. Government subsidies', 'B. Expansion of railroads and demand for beef in northern cities', 'C. Improved farming techniques', 'D. Immigration from Europe'], 'B', 'The expansion of railroads and growing demand for beef in northern markets drove the Texas cattle industry, leading to the famous cattle drives.', '5', 'hard'),
    mc('What is the significance of the Texas Declaration of Independence (1836)?', ['A. It declared war on Mexico', 'B. It formally stated Texas\'s reasons for separating from Mexico and established the Republic of Texas', 'C. It requested annexation to the United States', 'D. It established the Texas Constitution'], 'B', 'The Texas Declaration of Independence (March 2, 1836) listed grievances against Mexico and declared Texas an independent republic.', '1', 'medium'),
    mc('How does the three-branch system of Texas government prevent abuse of power?', ['A. It doesn\'t prevent abuse', 'B. Through checks and balances, each branch limits the power of the others', 'C. By giving all power to the governor', 'D. By requiring unanimous agreement on all decisions'], 'B', 'Texas\'s three branches (legislative, executive, judicial) have checks and balances to prevent any one branch from becoming too powerful.', '2', 'medium'),
    mc('What was the impact of the Civil War on Texas?', ['A. Texas was not affected', 'B. Texas joined the Confederacy, experienced economic hardship, and underwent Reconstruction', 'C. Texas remained neutral', 'D. Texas gained new territory'], 'B', 'Texas joined the Confederacy, suffered economic disruption during and after the war, and underwent Reconstruction (1865-1870).', '5', 'medium'),
    mc('Which Texas city is the state capital?', ['A. Houston', 'B. Dallas', 'C. San Antonio', 'D. Austin'], 'D', 'Austin has been the capital of Texas since 1839, when it was chosen as the capital of the Republic of Texas.', '2', 'easy'),
    mc('What is the significance of Juneteenth (June 19, 1865)?', ['A. Texas\'s independence from Mexico', 'B. The day enslaved people in Texas learned of their emancipation', 'C. The end of the Civil War', 'D. Texas\'s annexation to the United States'], 'B', 'On June 19, 1865, Union soldiers arrived in Galveston, Texas, announcing the end of slavery — more than two months after the Civil War ended.', '5', 'medium'),
    mc('How did Spanish colonization affect Texas?', ['A. It had no lasting impact', 'B. It introduced Spanish language, religion, architecture, and ranching culture', 'C. It only affected the coast', 'D. It led to immediate independence'], 'B', 'Spanish colonization (1690s-1821) introduced Catholicism, Spanish language, mission architecture, and ranching traditions that still influence Texas culture.', '4', 'medium'),
    mc('What is the role of the Texas Governor?', ['A. Make laws', 'B. Interpret laws', 'C. Execute and enforce state laws as head of the executive branch', 'D. Manage the Texas Legislature'], 'C', 'The Texas Governor is the chief executive officer of the state, responsible for implementing and enforcing state laws.', '2', 'easy'),
    mc('Which geographic feature forms the eastern boundary of the Texas Hill Country?', ['A. The Balcones Escarpment', 'B. The Rio Grande', 'C. The Red River', 'D. The Pecos River'], 'A', 'The Balcones Escarpment is a geological fault zone that forms the eastern and southern boundary of the Texas Hill Country.', '3', 'hard'),
    mc('What was the Texas Annexation (1845)?', ['A. Texas conquered Mexico', 'B. Texas was admitted to the United States as the 28th state', 'C. Texas became a territory of Spain', 'D. Texas merged with Louisiana'], 'B', 'Texas was annexed by the United States on December 29, 1845, becoming the 28th state after nine years as an independent republic.', '1', 'easy'),
    mc('How did the Mexican-American War (1846-1848) affect Texas?', ['A. Texas lost territory to Mexico', 'B. It confirmed the Rio Grande as the US-Mexico border and led to the Mexican Cession', 'C. Texas became independent again', 'D. It had no impact on Texas'], 'B', 'The Mexican-American War confirmed the Rio Grande as the Texas-Mexico border and resulted in the US acquiring California and the Southwest.', '1', 'hard'),
    mc('What is the importance of the Rio Grande to Texas?', ['A. It is only a water source', 'B. It forms the international border between Texas and Mexico and is a vital water resource', 'C. It is only important for agriculture', 'D. It has no strategic importance'], 'B', 'The Rio Grande forms the entire southern border between Texas and Mexico and is a critical water source for both countries.', '3', 'easy'),
    mc('Which Texas region has the most diverse economy, including technology, energy, and healthcare?', ['A. West Texas', 'B. The Panhandle', 'C. The Texas Triangle (Houston-Dallas-San Antonio-Austin)', 'D. East Texas'], 'C', 'The Texas Triangle metropolitan area contains the state\'s largest cities and most diverse economy, including energy, technology, healthcare, and finance.', '3', 'medium'),
    mc('What was the significance of the Texas Rangers in the 19th century?', ['A. They were only a baseball team', 'B. They served as a frontier law enforcement and military force protecting settlers', 'C. They enforced federal laws only', 'D. They were a private army'], 'B', 'The Texas Rangers were a frontier law enforcement organization that protected settlers from raids, enforced laws, and served as a military force.', '5', 'medium'),
    mc('How does the Texas economy today compare to its historical economy?', ['A. It is identical to the past', 'B. It has diversified from ranching and farming to include energy, technology, and international trade', 'C. It is less developed than in the past', 'D. It relies entirely on oil'], 'B', 'Texas has evolved from an economy based on cattle ranching and cotton farming to a diverse economy including energy, technology, aerospace, and international trade.', '5', 'medium'),
    mc('What is the purpose of the Texas Bill of Rights?', ['A. To list the duties of citizens', 'B. To protect the fundamental rights and freedoms of Texas citizens from government infringement', 'C. To establish the Texas court system', 'D. To define the powers of the governor'], 'B', 'The Texas Bill of Rights (Article I of the Texas Constitution) protects fundamental rights including free speech, religion, and due process.', '2', 'medium'),
    mc('Which Native American group originally inhabited the coastal plains of Texas?', ['A. Comanche', 'B. Karankawa', 'C. Apache', 'D. Wichita'], 'B', 'The Karankawa were indigenous people who lived along the Texas Gulf Coast, known for their fishing and hunter-gatherer lifestyle.', '4', 'medium'),
    mc('What was the impact of the Great Depression on Texas?', ['A. Texas was unaffected', 'B. It caused widespread unemployment, farm foreclosures, and the Dust Bowl in West Texas', 'C. Texas\'s economy grew during the Depression', 'D. Only urban areas were affected'], 'B', 'The Great Depression caused severe hardship in Texas, including farm failures, unemployment, and the Dust Bowl that devastated the Panhandle region.', '5', 'hard'),
    mc('How did World War II affect Texas?', ['A. Texas was not involved', 'B. Military bases, defense industries, and wartime production transformed the Texas economy', 'C. Texas\'s economy declined during the war', 'D. Only coastal cities were affected'], 'B', 'WWII brought military bases, defense industries, and economic growth to Texas, laying the foundation for the state\'s post-war industrial expansion.', '5', 'hard'),
  ];
}

// ─── G8KAPSCI Bank B (27 questions) ─────────────────────────────────────────
function getG8KAPSciB() {
  return [
    mc('What is the difference between speed, velocity, and acceleration?', ['A. They are all the same', 'B. Speed is magnitude; velocity adds direction; acceleration is rate of velocity change', 'C. Velocity is always greater than speed', 'D. Acceleration is the same as velocity'], 'B', 'Speed is scalar (magnitude only); velocity is vector (magnitude + direction); acceleration measures the rate of change of velocity.', '1', 'medium'),
    mc('Which law states that the force on an object equals its mass times acceleration?', ['A. Newton\'s First Law', 'B. Newton\'s Second Law', 'C. Newton\'s Third Law', 'D. Law of Gravitation'], 'B', 'Newton\'s Second Law: F = ma. The net force on an object equals its mass multiplied by its acceleration.', '1', 'easy'),
    mc('What is the difference between potential and kinetic energy?', ['A. They are the same', 'B. Potential energy is stored; kinetic energy is energy of motion', 'C. Kinetic energy is always greater', 'D. Potential energy only exists in springs'], 'B', 'Potential energy is stored energy (gravitational, elastic, chemical); kinetic energy is the energy of moving objects.', '2', 'easy'),
    mc('What is the atomic model?', ['A. A physical model of an atom', 'B. A theoretical representation of atomic structure showing protons, neutrons, and electrons', 'C. A chemical formula', 'D. A type of nuclear reaction'], 'B', 'The atomic model is a theoretical framework describing the structure of atoms, including the nucleus (protons, neutrons) and electron shells.', '3', 'easy'),
    mc('What is the difference between an element and a compound?', ['A. They are the same', 'B. An element has one type of atom; a compound has two or more different atoms chemically bonded', 'C. Compounds cannot be broken down', 'D. Elements are always gases'], 'B', 'An element consists of only one type of atom; a compound is formed when two or more different elements are chemically combined.', '3', 'easy'),
    mc('What is the role of the Sun in Earth\'s energy systems?', ['A. It has no role', 'B. It is the primary energy source driving weather, climate, photosynthesis, and ocean currents', 'C. It only affects temperature', 'D. It only affects ocean tides'], 'B', 'The Sun is Earth\'s primary energy source, driving atmospheric circulation, ocean currents, the water cycle, and photosynthesis.', '4', 'easy'),
    mc('What is the greenhouse effect?', ['A. Growing plants in greenhouses', 'B. The process by which greenhouse gases trap heat in Earth\'s atmosphere', 'C. The reflection of sunlight by clouds', 'D. The cooling of Earth\'s surface at night'], 'B', 'The greenhouse effect occurs when greenhouse gases (CO₂, water vapor, methane) absorb and re-emit infrared radiation, warming Earth\'s surface.', '4', 'medium'),
    mc('What is the difference between mitosis and meiosis in terms of purpose?', ['A. They have the same purpose', 'B. Mitosis is for growth and repair; meiosis is for sexual reproduction', 'C. Meiosis is for growth; mitosis is for reproduction', 'D. Only mitosis occurs in humans'], 'B', 'Mitosis produces identical cells for growth, repair, and asexual reproduction; meiosis produces gametes (sex cells) for sexual reproduction.', '5', 'medium'),
    mc('What is the central dogma of molecular biology?', ['A. DNA → RNA → Protein', 'B. Protein → RNA → DNA', 'C. RNA → DNA → Protein', 'D. Protein → DNA → RNA'], 'A', 'The central dogma describes the flow of genetic information: DNA is transcribed into RNA, which is translated into proteins.', '5', 'hard'),
    mc('Which type of rock cycle process involves the melting of rock?', ['A. Weathering', 'B. Metamorphism', 'C. Melting/Magma formation', 'D. Cementation'], 'C', 'When rocks are subjected to extreme heat, they melt to form magma, which can then cool to form igneous rocks.', '6', 'easy'),
    mc('What is the difference between weather and climate?', ['A. They are the same', 'B. Weather is short-term atmospheric conditions; climate is long-term average patterns', 'C. Climate changes daily; weather does not', 'D. Only climate affects humans'], 'B', 'Weather describes current atmospheric conditions (day-to-day); climate describes the average weather patterns over 30+ years.', '4', 'easy'),
    mc('What is the significance of the periodic table?', ['A. It lists all known compounds', 'B. It organizes elements by atomic number and reveals patterns in their properties', 'C. It shows only metals', 'D. It was created in the 20th century'], 'B', 'The periodic table organizes elements by atomic number and groups elements with similar properties, revealing patterns in chemical behavior.', '3', 'easy'),
    mc('What is the difference between ionic and covalent bonds?', ['A. They are the same', 'B. Ionic bonds involve electron transfer; covalent bonds involve electron sharing', 'C. Covalent bonds are stronger', 'D. Only ionic bonds form compounds'], 'B', 'Ionic bonds form when electrons are transferred between atoms (creating ions); covalent bonds form when atoms share electrons.', '3', 'hard'),
    mc('What is the role of decomposers in the carbon cycle?', ['A. They produce carbon dioxide through photosynthesis', 'B. They break down dead organisms, releasing carbon back into the atmosphere and soil', 'C. They absorb carbon from the atmosphere', 'D. They have no role in the carbon cycle'], 'B', 'Decomposers break down dead organic matter, releasing CO₂ back into the atmosphere and carbon compounds into the soil.', '7', 'medium'),
    mc('What is the difference between a physical and chemical property?', ['A. They are the same', 'B. Physical properties can be observed without changing composition; chemical properties describe reactivity', 'C. Chemical properties are easier to measure', 'D. Only physical properties are measurable'], 'B', 'Physical properties (color, density, melting point) can be measured without changing the substance; chemical properties describe how substances react.', '3', 'medium'),
    mc('What is the principle of natural selection?', ['A. Humans select which organisms survive', 'B. Organisms with traits better suited to their environment are more likely to survive and reproduce', 'C. All organisms have equal survival chances', 'D. Evolution occurs randomly'], 'B', 'Natural selection is the mechanism of evolution: organisms with favorable traits survive and reproduce more, passing those traits to offspring.', '5', 'medium'),
    mc('What is the difference between a mixture and a pure substance?', ['A. They are the same', 'B. A pure substance has uniform composition; a mixture contains two or more substances not chemically combined', 'C. Mixtures are always liquids', 'D. Pure substances cannot be separated'], 'B', 'A pure substance (element or compound) has uniform composition; a mixture contains two or more substances that can be separated by physical means.', '3', 'easy'),
    mc('What is the law of conservation of energy?', ['A. Energy can be created from nothing', 'B. Energy cannot be created or destroyed, only converted from one form to another', 'C. Energy always decreases', 'D. Kinetic energy is always conserved'], 'B', 'The law of conservation of energy states that the total energy in a closed system remains constant; energy changes form but is never created or destroyed.', '2', 'easy'),
    mc('What is the difference between a conductor and an insulator?', ['A. They are the same', 'B. Conductors allow electricity/heat to flow easily; insulators resist the flow', 'C. Insulators are better for electronics', 'D. Only metals can conduct electricity'], 'B', 'Conductors (metals) allow the free flow of electrons (electricity) or heat; insulators (rubber, wood) resist the flow of electricity or heat.', '2', 'medium'),
    mc('What is the significance of the water cycle for Earth\'s systems?', ['A. It only affects weather', 'B. It continuously moves water through the atmosphere, land, and oceans, supporting all life', 'C. It only matters for agriculture', 'D. It has no impact on climate'], 'B', 'The water cycle continuously moves water through evaporation, condensation, precipitation, and runoff, regulating climate and supporting all ecosystems.', '4', 'easy'),
    mc('What is the difference between a food chain and an energy pyramid?', ['A. They are identical', 'B. A food chain shows feeding relationships; an energy pyramid shows the decrease in energy at each trophic level', 'C. An energy pyramid shows more organisms', 'D. Food chains are more accurate'], 'B', 'A food chain shows who eats whom; an energy pyramid shows that only about 10% of energy transfers to the next trophic level.', '7', 'medium'),
    mc('What is the role of the ozone layer?', ['A. It traps heat near Earth\'s surface', 'B. It absorbs harmful ultraviolet radiation from the Sun', 'C. It produces oxygen for breathing', 'D. It reflects visible light'], 'B', 'The ozone layer in the stratosphere absorbs most of the Sun\'s harmful ultraviolet (UV) radiation, protecting life on Earth.', '4', 'easy'),
    mc('What is the difference between a hypothesis and a theory in science?', ['A. They are the same', 'B. A hypothesis is a testable prediction; a theory is a well-supported explanation backed by extensive evidence', 'C. A theory is less supported than a hypothesis', 'D. Only theories can be tested'], 'B', 'A hypothesis is a testable prediction; a scientific theory is a well-substantiated explanation supported by extensive testing and evidence.', 'prereq', 'easy'),
    mc('What is the significance of the Big Bang theory?', ['A. It explains how life began', 'B. It describes the origin and early evolution of the universe from an extremely hot, dense state', 'C. It explains the formation of Earth', 'D. It describes the formation of the solar system only'], 'B', 'The Big Bang theory describes how the universe began approximately 13.8 billion years ago from an extremely hot, dense state and has been expanding ever since.', '8', 'hard'),
    mc('What is the difference between renewable and non-renewable energy sources?', ['A. They are the same', 'B. Renewable sources replenish naturally; non-renewable sources are finite and take millions of years to form', 'C. Non-renewable sources are better for the environment', 'D. Renewable sources are always more expensive'], 'B', 'Renewable energy (solar, wind, hydro) replenishes naturally; non-renewable energy (fossil fuels) is finite and takes millions of years to form.', '8', 'easy'),
    mc('What is the role of enzymes in biological reactions?', ['A. They provide energy for reactions', 'B. They act as biological catalysts, speeding up chemical reactions without being consumed', 'C. They are consumed in reactions', 'D. They slow down reactions'], 'B', 'Enzymes are biological catalysts that lower the activation energy of chemical reactions, speeding them up without being permanently altered.', '5', 'hard'),
    mc('What is the significance of DNA replication?', ['A. It produces proteins', 'B. It ensures each new cell receives a complete copy of the genetic information', 'C. It occurs only during reproduction', 'D. It changes the genetic code'], 'B', 'DNA replication ensures that when a cell divides, each daughter cell receives an identical, complete copy of the parent cell\'s genetic information.', '5', 'medium'),
  ];
}

// ─── G8KAPSS Bank B (27 questions) ──────────────────────────────────────────
function getG8KAPSSb() {
  return [
    mc('What were the main causes of the American Revolution?', ['A. Only taxation without representation', 'B. A combination of taxation without representation, Enlightenment ideas, and colonial self-governance', 'C. Religious persecution', 'D. Trade disputes with France'], 'B', 'The American Revolution resulted from multiple causes: taxation without representation, Enlightenment philosophy, colonial self-governance traditions, and British policies after 1763.', '1', 'medium'),
    mc('What is the significance of the Declaration of Independence (1776)?', ['A. It ended the Revolutionary War', 'B. It declared the colonies\' independence and articulated Enlightenment principles of natural rights', 'C. It established the US Constitution', 'D. It created the federal government'], 'B', 'The Declaration of Independence declared separation from Britain and articulated Enlightenment principles including natural rights, popular sovereignty, and the right to revolution.', '1', 'medium'),
    mc('What were the weaknesses of the Articles of Confederation?', ['A. It gave too much power to the federal government', 'B. It gave too little power to the federal government, with no taxing authority or ability to regulate commerce', 'C. It had no Bill of Rights', 'D. It was too difficult to amend'], 'B', 'The Articles of Confederation created a weak central government with no power to tax, regulate commerce, or enforce laws, leading to the Constitutional Convention.', '1', 'hard'),
    mc('What is the significance of the Constitutional Convention (1787)?', ['A. It declared independence from Britain', 'B. It created the US Constitution, establishing a stronger federal government', 'C. It ended the Civil War', 'D. It established the Bill of Rights'], 'B', 'The Constitutional Convention produced the US Constitution, which replaced the Articles of Confederation with a stronger federal government with three branches.', '2', 'medium'),
    mc('What was Manifest Destiny?', ['A. The belief that the US should remain small', 'B. The 19th-century belief that the US was destined to expand across North America', 'C. A foreign policy of isolation', 'D. A religious movement'], 'B', 'Manifest Destiny was the widely held belief in the 19th century that American settlers were destined to expand across the continent to the Pacific Ocean.', '3', 'easy'),
    mc('What were the main causes of the Civil War?', ['A. Only slavery', 'B. A combination of slavery, states\' rights, economic differences, and political tensions', 'C. Only economic differences', 'D. Only political disagreements'], 'B', 'The Civil War resulted from multiple interconnected causes: slavery, states\' rights, economic differences between North and South, and political failures to compromise.', '4', 'medium'),
    mc('What was the significance of the Emancipation Proclamation (1863)?', ['A. It immediately freed all enslaved people', 'B. It declared enslaved people in Confederate states free and changed the war\'s purpose to include ending slavery', 'C. It ended the Civil War', 'D. It gave African Americans citizenship'], 'B', 'The Emancipation Proclamation declared enslaved people in Confederate states free and transformed the Civil War into a fight against slavery, discouraging European support for the Confederacy.', '4', 'hard'),
    mc('What were the goals of Reconstruction (1865-1877)?', ['A. To punish the South', 'B. To rebuild the South, integrate formerly enslaved people, and restore the Union', 'C. To expand westward', 'D. To industrialize the North'], 'B', 'Reconstruction aimed to rebuild the South, integrate formerly enslaved people as citizens, and restore the Confederate states to the Union.', '4', 'medium'),
    mc('What was the significance of the 13th, 14th, and 15th Amendments?', ['A. They established the three branches of government', 'B. They abolished slavery, granted citizenship, and gave Black men voting rights', 'C. They established women\'s suffrage', 'D. They expanded westward territories'], 'B', 'The Reconstruction Amendments abolished slavery (13th), granted citizenship and equal protection (14th), and prohibited denying voting rights based on race (15th).', '4', 'medium'),
    mc('What drove the Industrial Revolution in the United States?', ['A. Government planning', 'B. Technological innovation, natural resources, immigration, and railroad expansion', 'C. Foreign investment only', 'D. Agricultural surplus'], 'B', 'The US Industrial Revolution was driven by technological innovation, abundant natural resources, waves of immigrant labor, and the expansion of railroads.', '5', 'medium'),
    mc('What was the significance of the Louisiana Purchase (1803)?', ['A. It doubled the size of the US', 'B. It more than doubled the size of the US, opening the interior to expansion', 'C. It gave the US control of the Mississippi River only', 'D. It ended conflict with France'], 'B', 'The Louisiana Purchase (1803) nearly doubled the size of the United States, acquiring approximately 828,000 square miles from France for $15 million.', '3', 'easy'),
    mc('What was the impact of the Trail of Tears (1838-1839)?', ['A. It had no lasting impact', 'B. It forcibly removed Native Americans from their ancestral lands, causing thousands of deaths', 'C. It was a voluntary migration', 'D. It only affected the Cherokee Nation'], 'B', 'The Trail of Tears was the forced relocation of the Five Civilized Tribes from the southeastern US to Indian Territory, resulting in thousands of deaths from disease, exposure, and starvation.', '3', 'hard'),
    mc('What is the significance of the Monroe Doctrine (1823)?', ['A. It declared war on European powers', 'B. It warned European nations against further colonization or interference in the Western Hemisphere', 'C. It established trade agreements with Europe', 'D. It ended the War of 1812'], 'B', 'The Monroe Doctrine declared that the Western Hemisphere was closed to further European colonization and that any attempt to extend European influence would be considered a threat to US security.', '2', 'medium'),
    mc('What were the main effects of the Mexican-American War (1846-1848) on the United States?', ['A. The US lost territory', 'B. The US gained California, New Mexico, and other territories, intensifying the slavery debate', 'C. It had no territorial impact', 'D. It only confirmed the Texas border'], 'B', 'The Mexican-American War resulted in the Mexican Cession (California, Nevada, Utah, Arizona, New Mexico), which intensified the debate over the expansion of slavery.', '3', 'hard'),
    mc('What was the significance of the Missouri Compromise (1820)?', ['A. It ended slavery in Missouri', 'B. It temporarily resolved the slavery debate by admitting Missouri as a slave state and Maine as a free state', 'C. It expanded slavery to all territories', 'D. It abolished slavery north of the Ohio River'], 'B', 'The Missouri Compromise admitted Missouri as a slave state and Maine as a free state, and prohibited slavery north of the 36°30\' line in the Louisiana Territory.', '4', 'hard'),
    mc('What is the significance of the Bill of Rights?', ['A. It established the three branches of government', 'B. It protects individual freedoms from government infringement', 'C. It defined the powers of Congress', 'D. It was added to the Constitution in 1776'], 'B', 'The Bill of Rights (first 10 amendments, 1791) protects fundamental individual rights including free speech, religion, press, and due process.', '2', 'easy'),
    mc('What was the role of women in the early American Republic?', ['A. They had full political rights', 'B. They were largely excluded from political life but played vital roles in the household economy and early reform movements', 'C. They had no role in society', 'D. They controlled most businesses'], 'B', 'Women in the early Republic were largely excluded from voting and public office but were essential to the household economy and began organizing for reform in the early 19th century.', '6', 'medium'),
    mc('What was the significance of the Lewis and Clark Expedition (1804-1806)?', ['A. It found a route to Asia', 'B. It explored and mapped the Louisiana Purchase territory, establishing US claims to the Pacific Northwest', 'C. It discovered gold in California', 'D. It established trade with Native Americans only'], 'B', 'The Lewis and Clark Expedition explored the Louisiana Purchase territory, mapped routes to the Pacific, gathered scientific data, and established US claims to the Oregon Territory.', '3', 'medium'),
    mc('What were the main causes of westward expansion in the 19th century?', ['A. Government force only', 'B. Manifest Destiny, economic opportunities (land, gold), and transportation improvements', 'C. Overpopulation in the East only', 'D. Military conquest only'], 'B', 'Westward expansion was driven by Manifest Destiny ideology, economic opportunities (cheap land, gold rushes), technological improvements (railroads), and immigration.', '3', 'medium'),
    mc('What is the significance of the Compromise of 1850?', ['A. It ended the Civil War', 'B. It temporarily resolved sectional tensions over slavery in territories gained from Mexico', 'C. It abolished slavery in the South', 'D. It established popular sovereignty everywhere'], 'B', 'The Compromise of 1850 admitted California as a free state, established popular sovereignty in new territories, and strengthened the Fugitive Slave Act, temporarily easing sectional tensions.', '4', 'hard'),
    mc('What was the impact of the California Gold Rush (1848-1855)?', ['A. It had little impact', 'B. It accelerated California\'s population growth, statehood, and westward migration', 'C. It only benefited California', 'D. It ended Native American cultures in California'], 'B', 'The Gold Rush brought hundreds of thousands of migrants to California, accelerated its statehood (1850), transformed the economy, and devastated Native American populations.', '3', 'medium'),
    mc('What is the significance of the Kansas-Nebraska Act (1854)?', ['A. It ended slavery in Kansas', 'B. It repealed the Missouri Compromise and allowed popular sovereignty on slavery, intensifying sectional conflict', 'C. It established Kansas as a free state', 'D. It had little political impact'], 'B', 'The Kansas-Nebraska Act repealed the Missouri Compromise, allowed popular sovereignty on slavery in new territories, and led to "Bleeding Kansas" and the formation of the Republican Party.', '4', 'hard'),
    mc('What were the main effects of industrialization on American society?', ['A. It had no social effects', 'B. It created an urban working class, changed family structures, increased immigration, and led to labor movements', 'C. It only affected the wealthy', 'D. It decreased immigration'], 'B', 'Industrialization created a large urban working class, transformed family and gender roles, attracted massive immigration, and led to labor unions and reform movements.', '5', 'hard'),
    mc('What is the significance of the Underground Railroad?', ['A. It was a literal railroad', 'B. It was a network of people and safe houses that helped enslaved people escape to freedom', 'C. It only operated in the North', 'D. It was a government program'], 'B', 'The Underground Railroad was a secret network of abolitionists and safe houses that helped thousands of enslaved people escape from the South to freedom in the North or Canada.', '4', 'medium'),
    mc('What were the main provisions of the Northwest Ordinance (1787)?', ['A. It established the Louisiana Territory', 'B. It organized the Northwest Territory, established a process for statehood, and prohibited slavery north of the Ohio River', 'C. It gave land to veterans only', 'D. It established the first US territories in the West'], 'B', 'The Northwest Ordinance organized the territory north of the Ohio River, established a process for creating new states, guaranteed civil rights, and prohibited slavery in the territory.', '2', 'hard'),
    mc('What is the significance of the Federalist Papers?', ['A. They opposed the Constitution', 'B. They argued for ratification of the Constitution and explained its principles', 'C. They established the Bill of Rights', 'D. They were written after ratification'], 'B', 'The Federalist Papers (1787-1788), written by Hamilton, Madison, and Jay, argued for ratification of the Constitution and remain important interpretations of its principles.', '2', 'hard'),
    mc('What was the impact of the War of 1812 on the United States?', ['A. The US lost territory', 'B. It strengthened American nationalism, ended British support for Native Americans, and boosted domestic manufacturing', 'C. It had no lasting impact', 'D. It led to the Louisiana Purchase'], 'B', 'The War of 1812 fostered American nationalism, ended British interference in the Northwest, and stimulated domestic manufacturing by cutting off British imports.', '1', 'hard'),
  ];
}

// ─── APHG Bank B (27 questions) ──────────────────────────────────────────────
function getAPHGb() {
  return [
    mc('What is the difference between absolute and relative location?', ['A. They are the same', 'B. Absolute location uses coordinates; relative location describes position in relation to other places', 'C. Relative location uses GPS', 'D. Absolute location is less precise'], 'B', 'Absolute location uses coordinates (latitude/longitude); relative location describes a place in relation to other known places.', '1', 'easy'),
    mc('What is the concept of "sense of place" in human geography?', ['A. The physical location of a place', 'B. The subjective feelings and meanings people attach to a place', 'C. The economic value of a location', 'D. The political boundaries of a region'], 'B', 'Sense of place refers to the subjective, emotional attachment and meaning people give to specific locations based on personal experiences and cultural associations.', '1', 'medium'),
    mc('What is the demographic transition model?', ['A. A model of migration patterns', 'B. A model describing how birth and death rates change as countries develop economically', 'C. A model of urban growth', 'D. A model of agricultural development'], 'B', 'The demographic transition model describes the shift from high birth/death rates (pre-industrial) to low birth/death rates (post-industrial) as countries develop.', '2', 'medium'),
    mc('What is the difference between push and pull factors in migration?', ['A. They are the same', 'B. Push factors drive people away from a place; pull factors attract people to a new place', 'C. Pull factors are always economic', 'D. Push factors are always political'], 'B', 'Push factors (war, poverty, natural disasters) drive people away from their home; pull factors (economic opportunity, safety, family) attract them to a new place.', '2', 'easy'),
    mc('What is the concept of cultural landscape?', ['A. A natural landscape', 'B. The visible imprint of human activity on the natural landscape', 'C. A landscape protected from development', 'D. A landscape with no human influence'], 'B', 'A cultural landscape is the modification of the natural landscape by human activity, including buildings, roads, farms, and other human-made features.', '3', 'easy'),
    mc('What is the difference between a language family and a language branch?', ['A. They are the same', 'B. A language family is the broadest grouping; a language branch is a subdivision within a family', 'C. A language branch is broader', 'D. Language families are smaller than branches'], 'B', 'A language family (e.g., Indo-European) is the broadest classification; branches (e.g., Germanic, Romance) are subdivisions sharing a more recent common ancestor.', '3', 'medium'),
    mc('What is the concept of "universalizing religion" vs. "ethnic religion"?', ['A. They are the same', 'B. Universalizing religions seek converts worldwide; ethnic religions are tied to specific groups/places', 'C. Ethnic religions are more common', 'D. Universalizing religions are older'], 'B', 'Universalizing religions (Christianity, Islam, Buddhism) actively seek converts; ethnic religions (Judaism, Hinduism) are tied to specific ethnic groups or geographic areas.', '3', 'medium'),
    mc('What is the von Thünen model?', ['A. A model of urban land use', 'B. A model explaining agricultural land use patterns around a central market city', 'C. A model of industrial location', 'D. A model of migration'], 'B', 'Von Thünen\'s model (1826) explains how agricultural land use is organized in concentric rings around a central market, based on transportation costs and land value.', '4', 'hard'),
    mc('What is the difference between subsistence and commercial agriculture?', ['A. They are the same', 'B. Subsistence farming produces food for the farmer\'s family; commercial farming produces for market sale', 'C. Commercial farming is less productive', 'D. Subsistence farming uses more technology'], 'B', 'Subsistence agriculture produces food primarily for the farmer\'s own consumption; commercial agriculture produces crops for sale in markets.', '4', 'easy'),
    mc('What is the concept of "agglomeration" in industrial geography?', ['A. The spread of industries across a wide area', 'B. The clustering of related industries in a geographic area for mutual benefit', 'C. The decline of industrial regions', 'D. Government control of industry'], 'B', 'Agglomeration refers to the clustering of related industries and businesses in a geographic area, allowing them to share infrastructure, labor pools, and suppliers.', '5', 'hard'),
    mc('What is the difference between a primate city and a rank-size rule?', ['A. They are the same', 'B. A primate city is disproportionately large; the rank-size rule describes a regular hierarchy of city sizes', 'C. The rank-size rule applies only to developing countries', 'D. Primate cities always follow the rank-size rule'], 'B', 'A primate city is much larger than the next largest city; the rank-size rule states that the nth largest city has 1/n the population of the largest city.', '6', 'hard'),
    mc('What is the concept of "urban sprawl"?', ['A. Planned urban development', 'B. The uncontrolled expansion of urban areas into surrounding rural land', 'C. The growth of city centers', 'D. The decline of suburban areas'], 'B', 'Urban sprawl refers to the uncontrolled, low-density expansion of urban areas into surrounding rural and agricultural land, often car-dependent.', '6', 'easy'),
    mc('What is the difference between a nation and a state in political geography?', ['A. They are the same', 'B. A nation is a group sharing culture/identity; a state is a sovereign political entity with territory', 'C. A state is a cultural group', 'D. Nations always have their own governments'], 'B', 'A nation is a group of people sharing a common culture, language, or history; a state (country) is a sovereign political entity with defined territory and government.', '7', 'medium'),
    mc('What is the concept of "centripetal" vs. "centrifugal" forces in political geography?', ['A. They are the same', 'B. Centripetal forces unite a state; centrifugal forces divide it', 'C. Centrifugal forces are always stronger', 'D. Only centripetal forces affect modern states'], 'B', 'Centripetal forces (shared language, national identity, strong government) hold a state together; centrifugal forces (ethnic divisions, regional inequality) pull it apart.', '7', 'hard'),
    mc('What is the Heartland Theory (Mackinder)?', ['A. A theory about urban growth', 'B. A geopolitical theory that whoever controls the Eurasian heartland controls the world', 'C. A theory about agricultural regions', 'D. A theory about ocean power'], 'B', 'Mackinder\'s Heartland Theory (1904) argued that control of the Eurasian "heartland" (Eastern Europe/Central Asia) would give a power control over the "World Island" and ultimately the world.', '7', 'hard'),
    mc('What is the concept of "sense of place" vs. "placelessness"?', ['A. They are the same', 'B. Sense of place involves unique local identity; placelessness describes uniform, standardized environments', 'C. Placelessness is more common in rural areas', 'D. Sense of place is always positive'], 'B', 'Sense of place involves the unique identity and meaning of a location; placelessness (Relph) describes the homogenization of places due to globalization and standardization.', '1', 'hard'),
    mc('What is the difference between formal, functional, and perceptual regions?', ['A. They are the same', 'B. Formal regions have uniform characteristics; functional regions are organized around a node; perceptual regions are based on perception', 'C. Perceptual regions are most accurate', 'D. Functional regions have no center'], 'B', 'Formal (uniform) regions share common characteristics; functional (nodal) regions are organized around a central place; perceptual (vernacular) regions are based on people\'s mental maps.', '1', 'medium'),
    mc('What is the concept of "time-space compression"?', ['A. The slowing of transportation', 'B. The perception that the world is shrinking due to improved transportation and communication', 'C. The expansion of time zones', 'D. The compression of geographic space'], 'B', 'Time-space compression (Harvey) describes how advances in transportation and communication have reduced the effective distance between places, making the world feel smaller.', '5', 'hard'),
    mc('What is the significance of the Green Revolution?', ['A. An environmental movement', 'B. The introduction of high-yield crop varieties, fertilizers, and irrigation that dramatically increased food production', 'C. The conversion to organic farming', 'D. The spread of vegetarianism'], 'B', 'The Green Revolution (1960s-70s) introduced high-yield varieties, synthetic fertilizers, and irrigation to developing countries, dramatically increasing food production but also raising environmental concerns.', '4', 'medium'),
    mc('What is the difference between "core" and "periphery" in world-systems theory?', ['A. They are the same', 'B. Core countries are wealthy and dominant; periphery countries are less developed and economically dependent', 'C. Periphery countries are wealthier', 'D. Core countries are geographically central'], 'B', 'Wallerstein\'s world-systems theory divides countries into core (wealthy, dominant), semi-periphery (intermediate), and periphery (less developed, economically dependent on core).', '5', 'hard'),
    mc('What is the concept of "sequent occupance"?', ['A. The study of current land use', 'B. The idea that successive cultures leave their imprint on a landscape, creating a layered cultural landscape', 'C. The sequence of urban development', 'D. The order of agricultural development'], 'B', 'Sequent occupance describes how different cultures successively occupy the same area, each leaving its imprint on the landscape, creating a palimpsest of cultural layers.', '3', 'hard'),
    mc('What is the difference between "gentrification" and "suburbanization"?', ['A. They are the same', 'B. Gentrification is the renovation of urban neighborhoods by wealthier residents; suburbanization is movement to suburbs', 'C. Suburbanization occurs in city centers', 'D. Gentrification always displaces wealthy residents'], 'B', 'Gentrification involves wealthier residents moving into and renovating lower-income urban neighborhoods, often displacing original residents; suburbanization is the movement of people to suburban areas.', '6', 'medium'),
    mc('What is the concept of "cultural hearth"?', ['A. A type of fireplace', 'B. The geographic origin of a major culture or cultural innovation', 'C. The center of a cultural region', 'D. A place where cultures mix'], 'B', 'A cultural hearth is the geographic area where a major culture, civilization, or cultural innovation originated and from which it diffused to other areas.', '3', 'easy'),
    mc('What is the significance of the Burgess concentric zone model?', ['A. It describes agricultural land use', 'B. It describes urban land use in concentric rings expanding from the CBD', 'C. It describes industrial location', 'D. It describes suburban development'], 'B', 'Burgess\'s concentric zone model (1925) describes urban land use in rings: CBD, transition zone, working-class housing, middle-class housing, and commuter zone.', '6', 'medium'),
    mc('What is the difference between "assimilation" and "multiculturalism"?', ['A. They are the same', 'B. Assimilation involves adopting the dominant culture; multiculturalism values maintaining diverse cultural identities', 'C. Multiculturalism requires assimilation', 'D. Assimilation is always voluntary'], 'B', 'Assimilation is the process of adopting the dominant culture\'s language, customs, and values; multiculturalism values the preservation of diverse cultural identities within a society.', '3', 'medium'),
    mc('What is the concept of "environmental determinism" vs. "possibilism"?', ['A. They are the same', 'B. Environmental determinism says environment controls human behavior; possibilism says humans can adapt to and modify environments', 'C. Possibilism is an older theory', 'D. Environmental determinism is more accepted today'], 'B', 'Environmental determinism (largely discredited) held that the physical environment determines human behavior; possibilism argues that while the environment sets limits, humans have choices in how they respond.', '1', 'hard'),
    mc('What is the significance of the Rostow Modernization Model?', ['A. It describes agricultural development', 'B. It describes five stages of economic development from traditional society to high mass consumption', 'C. It describes urban growth patterns', 'D. It describes population growth'], 'B', 'Rostow\'s Modernization Model (1960) describes five stages of economic development: traditional society, preconditions for takeoff, takeoff, drive to maturity, and high mass consumption.', '5', 'hard'),
  ];
}

